-- 브랜드별 매출(주차) 적재 — 496건 (2025/11~2026/03, 마진=광고 전)
create table if not exists public.brand_sales (
  id uuid primary key default gen_random_uuid(),
  period_date date not null, year int not null, month int not null, week int not null,
  brand text not null, qty integer default 0, sales numeric default 0, margin numeric default 0,
  created_at timestamptz default now()
);
alter table public.brand_sales enable row level security;
drop policy if exists "temp_anon_all_brand_sales" on public.brand_sales;
create policy "temp_anon_all_brand_sales" on public.brand_sales for all to anon using (true) with check (true);
create index if not exists brand_sales_date_idx on public.brand_sales (period_date);
notify pgrst, 'reload schema';
